export class themeSwitcher{constructor(e){this.defaultTheme=e||"light",this.body=document.querySelector("body"),this.themeSwitcher=document.querySelectorAll("[data-bs-theme-value]"),this.themeIconActive=document.querySelector(".theme-icon-active > use"),this.init()}init(){this.themeSwitcher.forEach((e=>{e.addEventListener("click",(()=>{this.resetSwitch(this.themeSwitcher);const t=e.dataset.bsThemeValue;e.setAttribute("aria-pressed","true"),e.classList.add("active"),this.body.setAttribute("data-bs-theme",t),this.setIcon(e)}))})),this.resetSwitch(this.themeSwitcher);const e=this.body.querySelector(`[data-bs-theme-value="${this.defaultTheme}"]`);e.setAttribute("aria-pressed","true"),e.classList.add("active"),this.setIcon(e)}resetSwitch(e){e.forEach((e=>{e.setAttribute("aria-pressed","false"),e.classList.remove("active")}))}setIcon(e){const t=e.querySelector(".theme-icon > use").getAttribute("href");this.themeIconActive.setAttribute("href",t)}}